 1	import type { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 4	
 5	import { ProviderModelRef, type V1beta1Provider } from '@kubev2v/types';
 6	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Button,
 9	  ButtonVariant,
10	  Flex,
11	  FlexItem,
12	  HelperText,
13	  HelperTextItem,
14	} from '@patternfly/react-core';
15	import { getType } from '@utils/crds/common/selectors';
16	import { useForkliftTranslation } from '@utils/i18n';
17	import { type ValidationMsg, ValidationState } from '@utils/validation/Validation';
18	
19	type ProviderCreateActionsSectionProps = {
20	  newProvider: V1beta1Provider;
21	  projectName: string;
22	  activeNamespace?: string | undefined;
23	  validationError: ValidationMsg;
24	  isLoading: boolean;
25	  onUpdate: () => void;
26	};
27	
28	const ProviderCreateActionsSection: FC<ProviderCreateActionsSectionProps> = ({
29	  activeNamespace,
30	  isLoading,
31	  newProvider,
32	  onUpdate,
33	  projectName,
34	  validationError,
35	}) => {
36	  const { t } = useForkliftTranslation();
37	  const navigate = useNavigate();
38	  const [, setActiveNamespace] = useActiveNamespace();
39	
40	  const providersListURL = getResourceUrl({
41	    namespace: activeNamespace,
42	    reference: ProviderModelRef,
43	  });
44	
45	  const onCancelClick = () => {
46	    navigate(providersListURL);
47	  };
48	
49	  return (
50	    <>
51	      <Flex>
52	        <FlexItem>
53	          <Button
54	            data-testid="create-provider-button"
55	            variant={ButtonVariant.primary}
56	            isDisabled={validationError?.type === ValidationState.Error}
57	            isLoading={isLoading}
58	            onClick={() => {
59	              setActiveNamespace(projectName);
60	              onUpdate();
61	            }}
62	          >
63	            {t('Create provider')}
64	          </Button>
65	        </FlexItem>
66	        <FlexItem>
67	          <Button onClick={onCancelClick} variant={ButtonVariant.secondary}>
68	            {t('Cancel')}
69	          </Button>
70	        </FlexItem>
71	      </Flex>
72	      <HelperText className="forklift-create-subtitle-errors">
73	        {validationError?.type === ValidationState.Error && getType(newProvider) ? (
74	          <HelperTextItem variant="error">{validationError?.msg}</HelperTextItem>
75	        ) : (
76	          <HelperTextItem variant="indeterminate">{t('Create new provider')}</HelperTextItem>
77	        )}
78	      </HelperText>
79	    </>
80	  );
81	};
82	
83	export default ProviderCreateActionsSection;

